/**
 * Unit tests for the per-entity integration change-emitter emitter
 * (EMIT-CHANGES seam).
 *
 * Pure-function tests — no filesystem. Cover:
 *   (a) the @generated banner (fully regenerated, no emit-once sentinel);
 *   (b) the class name + `IIntegrationChangeEmitter` implements clause;
 *   (c) the action → `<entity>_<verb>` mapping uses `_edited`, NOT `_updated`;
 *   (d) the payload carries the `source: 'integration'` provenance marker +
 *       conditional changedFields;
 *   (e) the TYPED_EVENT_BUS injection + publish call;
 *   (f) package vs vendored import specifiers (ADR-037).
 */

import { describe, expect, test } from "bun:test";
import {
  generateChangeEmitter,
  changeEmitterClass,
  type ChangeEmitterEmitInput,
} from "../../cli/shared/change-emitter-emission-generator";

const messageInput: ChangeEmitterEmitInput = {
  entityName: "message",
  entityClass: "Message",
  surface: "messaging",
  sourceDesc: "definitions entity 'message' (integration.sink.emit_changes)",
};

describe("changeEmitterClass — naming", () => {
  test("is <Entity>ChangeEmitter", () => {
    expect(changeEmitterClass("Message")).toBe("MessageChangeEmitter");
    expect(changeEmitterClass("CallRecording")).toBe("CallRecordingChangeEmitter");
  });
});

describe("generateChangeEmitter — output contract", () => {
  const out = generateChangeEmitter(messageInput);

  test("carries the @generated banner (re-emit, never hand-edit) — no emit-once sentinel", () => {
    expect(out).toContain("// @generated by @pattern-stack/codegen");
    expect(out).not.toContain("<CODEGEN-SCAFFOLD-V1>");
  });

  test("class name + implements IIntegrationChangeEmitter", () => {
    expect(out).toContain(
      "export class MessageChangeEmitter implements IIntegrationChangeEmitter",
    );
  });

  test("injects the TYPED_EVENT_BUS token, typed as the local structural publisher", () => {
    expect(out).toContain("@Inject(TYPED_EVENT_BUS) private readonly bus: ChangeEventPublisher");
    // Decoupled from both union-bound TypedEventBus types (package + consumer).
    expect(out).toContain("interface ChangeEventPublisher {");
    expect(out).not.toContain("import type { TypedEventBus }");
  });

  test("maps action → typed event name; uses `_edited`, NEVER `_updated`", () => {
    expect(out).toContain("'message_created'");
    expect(out).toContain("'message_edited'");
    expect(out).toContain("'message_deleted'");
    expect(out).not.toContain("'message_updated'");
    // created branch, then edited fallback for updated, then deleted.
    expect(out).toContain("notification.action === 'created'");
    expect(out).toContain("notification.action === 'updated'");
  });

  test("payload carries the source:'integration' provenance marker + identity", () => {
    expect(out).toContain("entityId: notification.entityId,");
    expect(out).toContain("externalId: notification.externalId,");
    expect(out).toContain("provider: notification.provider,");
    expect(out).toContain("source: 'integration',");
  });

  test("changedFields forwarded only when present (created/edited)", () => {
    expect(out).toContain("if (notification.changedFields !== undefined)");
    expect(out).toContain("payload['changedFields'] = notification.changedFields;");
  });

  test("publishes via the bus with aggregateId = entityId and the tx/tenant opts", () => {
    expect(out).toContain("await this.bus.publish(type, notification.entityId, payload,");
    expect(out).toContain("tx: notification.tx,");
    expect(out).toContain("tenantId: notification.tenantId");
  });

  test("package mode imports from @pattern-stack/codegen/subsystems (events token + integration types)", () => {
    expect(out).toContain("import { TYPED_EVENT_BUS } from '@pattern-stack/codegen/subsystems';");
    expect(out).toContain(
      "import type {\n  IIntegrationChangeEmitter,\n  IntegrationChangeNotification,\n} from '@pattern-stack/codegen/subsystems';",
    );
  });
});

describe("generateChangeEmitter — vendored mode (ADR-037)", () => {
  const out = generateChangeEmitter({ ...messageInput, mode: "vendored" });

  test("imports flip to the @shared/subsystems vendored barrels", () => {
    expect(out).toContain("from '@shared/subsystems/events'");
    expect(out).toContain("from '@shared/subsystems/integration'");
    expect(out).not.toContain("@pattern-stack/codegen/subsystems");
  });
});
